,mBAAO,CAAC,kPAAqO;AACpQ;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED;;;;;;;;ACxCA;AACA,yBAAyB,mBAAO,CAAC,uDAAkE;AACnG;AACA,qBAAqB,mBAAO,CAAC,sbAAgY;AAC7Z;AACA,uBAAuB,mBAAO,CAAC,2QAA2P;AAC1R;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED;;;;;;;;ACxCA;AACA;AACA;AACA,EAAE,mBAAO,CAAC,gVAAgR;AAC1R;AACA,yBAAyB,mBAAO,CAAC,uDAAkE;AACnG;AACA,qBAAqB,mBAAO,CAAC,qaAA+W;AAC5Y;AACA,uBAAuB,mBAAO,CAAC,0PAA0O;AACzQ;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED;;;;;;;;AC5CA;AACA,yBAAyB,mBAAO,CAAC,uDAAkE;AACnG;AACA,qBAAqB,mBAAO,CAAC,2aAAqX;AAClZ;AACA,uBAAuB,mBAAO,CAAC,gQAAgP;AAC/Q;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"tenat-tem-sets-indexjs/ .js","sourcesContent":["<template>\r\n    <div>\r\n        <div class=\"row \">\r\n            <div class=\"col-md-12 col-lg-12 col-xl-12 \">\r\n                <div class=\"row\" v-if=\"applyFilter\">\r\n                    <div class=\"col-lg-4 col-md-4 col-sm-12 pb-2\">\r\n                        <div class=\"d-flex\">\r\n                            <div style=\"width:100px\">\r\n                                Filtrar por:\r\n                            </div>\r\n                            <el-select\r\n                                v-model=\"search.column\"\r\n                                placeholder=\"Select\"\r\n                                @change=\"changeClearInput\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"(label, key) in columns\"\r\n                                    :key=\"key\"\r\n                                    :value=\"key\"\r\n                                    :label=\"label\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-lg-3 col-md-4 col-sm-12 pb-2\">\r\n                        <template\r\n                            v-if=\"\r\n                                search.column == 'date_of_issue' ||\r\n                                    search.column == 'date_of_due' ||\r\n                                    search.column == 'date_of_payment' ||\r\n                                    search.column == 'delivery_date' ||\r\n                                    search.column == 'date'\r\n                            \"\r\n                        >\r\n                            <template\r\n                                v-if=\"resource != 'restaurant/worker/expenses'\"\r\n                            >\r\n                                <el-date-picker\r\n                                    v-model=\"search.value\"\r\n                                    type=\"date\"\r\n                                    style=\"width: 100%;\"\r\n                                    placeholder=\"Buscar\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                    @change=\"getRecords\"\r\n                                >\r\n                                </el-date-picker>\r\n                            </template>\r\n                            <template v-else>\r\n                                <el-date-picker\r\n                                    v-model=\"search.value\"\r\n                                    type=\"daterange\"\r\n                                    range-separator=\"A\"\r\n                                    start-placeholder=\"Desde\"\r\n                                    value-format=\"yyyy-MM-dd\"\r\n                                    end-placeholder=\"Hasta\"\r\n                                    @change=\"getRecords\"\r\n                                >\r\n                                </el-date-picker>\r\n                            </template>\r\n                        </template>\r\n                        <template v-else-if=\"search.column == 'district_id'\">\r\n                            <el-select\r\n                                v-model=\"search.value\"\r\n                                @change=\"getRecords\"\r\n                                placeholder=\"Seleccione el Distrito\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"item in array_district\"\r\n                                    :key=\"item.id\"\r\n                                    :label=\"item.description\"\r\n                                    :value=\"item.id\"\r\n                                >\r\n                                </el-option>\r\n                            </el-select>\r\n                        </template>\r\n                        <template v-else>\r\n                            <el-input\r\n                                placeholder=\"Buscar\"\r\n                                v-model=\"search.value\"\r\n                                style=\"width: 100%;\"\r\n                                prefix-icon=\"el-icon-search\"\r\n                                @input=\"getRecords\"\r\n                            >\r\n                            </el-input>\r\n                        </template>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div\r\n                v-if=\"\r\n                    resource == 'restaurant/worker/expenses' &&\r\n                        records.length != 0\r\n                \"\r\n                class=\"row\"\r\n            >\r\n                <div class=\"col-md-3\">\r\n                    <el-button\r\n                        class=\"submit\"\r\n                        type=\"danger\"\r\n                        icon=\"el-icon-tickets\"\r\n                        @click.prevent=\"clickDownload('pdf')\"\r\n                        >Exportar PDF</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n            <div class=\"col-md-12\">\r\n                <div class=\"table-responsive\">\r\n                    <table class=\"table\">\r\n                        <thead>\r\n                            <slot name=\"heading\"></slot>\r\n                        </thead>\r\n                        <tbody>\r\n                            <slot\r\n                                v-for=\"(row, index) in records\"\r\n                                :row=\"row\"\r\n                                :index=\"customIndex(index)\"\r\n                            ></slot>\r\n                        </tbody>\r\n                    </table>\r\n                    <div>\r\n                        <el-pagination\r\n                            @current-change=\"getRecords\"\r\n                            layout=\"total, prev, pager, next\"\r\n                            :total=\"pagination.total\"\r\n                            :current-page.sync=\"pagination.current_page\"\r\n                            :page-size=\"pagination.per_page\"\r\n                        >\r\n                        </el-pagination>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nimport moment from \"moment\";\r\nimport queryString from \"query-string\";\r\n\r\nexport default {\r\n    props: {\r\n        resource: String,\r\n        applyFilter: {\r\n            type: Boolean,\r\n            default: true,\r\n            required: false\r\n        },\r\n        fromAdmin: {\r\n            type: Boolean,\r\n            default: false,\r\n            required: false\r\n        },\r\n        config: Object\r\n    },\r\n    data() {\r\n        return {\r\n            search: {\r\n                column: null,\r\n                value: null\r\n            },\r\n            columns: [],\r\n            records: [],\r\n            pagination: {},\r\n            array_district: [],\r\n            time: null\r\n        };\r\n    },\r\n    computed: {},\r\n    created() {\r\n        this.$eventHub.$on(\"reloadData\", () => {\r\n            this.getRecords();\r\n        });\r\n    },\r\n    async mounted() {\r\n        let column_resource = this.resource; // _.split(this.resource, '/')\r\n        await this.$http.get(`/${this.resource}/columns`).then(response => {\r\n            this.columns = response.data;\r\n            this.search.column = _.head(Object.keys(this.columns));\r\n        });\r\n        await this.getRecords();\r\n    },\r\n    methods: {\r\n        clickDownload() {\r\n            this.$emit(\"clickReport\", this.search);\r\n        },\r\n\r\n        customIndex(index) {\r\n            return (\r\n                this.pagination.per_page * (this.pagination.current_page - 1) +\r\n                index +\r\n                1\r\n            );\r\n        },\r\n        getRecords() {\r\n            if (this.time) {\r\n                clearTimeout(this.time);\r\n            }\r\n            //   this.$http.get(`/filtrar_distritos/records`)\r\n            // .then(response => {\r\n            //     this.array_district = response.data.district\r\n\r\n            // })\r\n            this.time = setTimeout(async () => {\r\n                let url = `/${\r\n                    this.resource\r\n                }/records?${this.getQueryParameters()}`;\r\n                if (this.fromAdmin) {\r\n                    url = `/${\r\n                        this.resource\r\n                    }/records?${this.getQueryParameters()}&fromAdmin=true`;\r\n                }\r\n                return this.$http.get(url).then(response => {\r\n                    this.records = response.data.data;\r\n                    this.pagination = response.data.meta;\r\n                    this.pagination.per_page = parseInt(\r\n                        response.data.meta.per_page\r\n                    );\r\n                });\r\n            }, 350);\r\n        },\r\n        getQueryParameters() {\r\n            if (\r\n                this.search.column == \"date\" &&\r\n                this.search.value &&\r\n                typeof this.search.value == \"object\"\r\n            ) {\r\n                this.search.value = this.search.value.join(\",\");\r\n            }\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                limit: this.limit,\r\n                value: this.search.value,\r\n                column: this.search.column\r\n            });\r\n        },\r\n        changeClearInput() {\r\n            this.search.value = \"\";\r\n            this.getRecords();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/components/DataTable.vue","<template>\r\n    <el-dialog\r\n        width=\"65%\"\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        :close-on-click-modal=\"false\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        top=\"7vh\"\r\n    >\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <!-- <div class=\"col-md-6\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.description}\">\r\n                            <label class=\"control-label\">Descripción <span class=\"text-danger\">*</span></label>\r\n                            <el-input v-model=\"form.description\" dusk=\"description\"></el-input>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.description\" v-text=\"errors.description[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.description }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre<span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.description\"\r\n                                dusk=\"description\"\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.description\"\r\n                                v-text=\"errors.description[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{\r\n                                'has-danger':\r\n                                    errors.sale_affectation_igv_type_id\r\n                            }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Lugar de Preparación</label\r\n                            >\r\n                            <el-select v-model=\"form.area_id\">\r\n                                <el-option\r\n                                    v-for=\"option in areas\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.sale_affectation_igv_type_id\"\r\n                                v-text=\"errors.sale_affectation_igv_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.second_name }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Nombre secundario\r\n                            </label>\r\n                            <el-input\r\n                                v-model=\"form.second_name\"\r\n                                dusk=\"second_name\"\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.second_name\"\r\n                                v-text=\"errors.second_name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <!-- <div class=\"col-md-9\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.name}\">\r\n                            <label class=\"control-label\">Nombre  <span class=\"text-danger\">*</span></label>\r\n                            <el-input v-model=\"form.name\" dusk=\"name\"></el-input>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.name\" v-text=\"errors.name[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n                    <div class=\"col-md-9\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.name }\"\r\n                        >\r\n                            <label class=\"control-label\">Descripción</label>\r\n                            <el-input\r\n                                v-model=\"form.name\"\r\n                                dusk=\"name\"\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.name\"\r\n                                v-text=\"errors.name[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.unit_type_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Unidad</label>\r\n                            <el-select\r\n                                v-model=\"form.unit_type_id\"\r\n                                dusk=\"unit_type_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in unit_types\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.unit_type_id\"\r\n                                v-text=\"errors.unit_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <!-- <div class=\"col-md-6\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.individual_items}\">\r\n                            <label class=\"control-label\">Elegir productos</label>\r\n                            <el-select v-model=\"form.individual_items\" filterable multiple collapse-tags @change=\"changeIndividualItems\" >\r\n                                <el-option v-for=\"option in individual_items\" :key=\"option.id\" :value=\"option.id\" :label=\"option.full_description\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.individual_items\" v-text=\"errors.individual_items[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.currency_type_id }\"\r\n                        >\r\n                            <label class=\"control-label\">Moneda</label>\r\n                            <el-select\r\n                                v-model=\"form.currency_type_id\"\r\n                                dusk=\"currency_type_id\"\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in currency_types\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.description\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.currency_type_id\"\r\n                                v-text=\"errors.currency_type_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.sale_unit_price }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Precio Unitario (Venta)\r\n                                <span class=\"text-danger\">*</span></label\r\n                            >\r\n                            <el-input\r\n                                v-model=\"form.sale_unit_price\"\r\n                                dusk=\"sale_unit_price\"\r\n                                @input=\"calculatePercentageOfProfitBySale\"\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.sale_unit_price\"\r\n                                v-text=\"errors.sale_unit_price[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.category_id }\"\r\n                        >\r\n                            <label class=\"control-label\">\r\n                                Categoría\r\n                            </label>\r\n\r\n                            <a\r\n                                href=\"#\"\r\n                                v-if=\"form_category.add == false\"\r\n                                class=\"control-label font-weight-bold text-info\"\r\n                                @click=\"form_category.add = true\"\r\n                            >\r\n                                [ + Nuevo]</a\r\n                            >\r\n                            <a\r\n                                href=\"#\"\r\n                                v-if=\"form_category.add == true\"\r\n                                class=\"control-label font-weight-bold text-info\"\r\n                                @click=\"saveCategory()\"\r\n                            >\r\n                                [ + Guardar]</a\r\n                            >\r\n                            <a\r\n                                href=\"#\"\r\n                                v-if=\"form_category.add == true\"\r\n                                class=\"control-label font-weight-bold text-danger\"\r\n                                @click=\"form_category.add = false\"\r\n                            >\r\n                                [ Cancelar]</a\r\n                            >\r\n                            <el-input\r\n                                v-if=\"form_category.add == true\"\r\n                                v-model=\"form_category.name\"\r\n                                dusk=\"item_code\"\r\n                                style=\"margin-bottom:1.5%;\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n\r\n                            <el-select\r\n                                v-if=\"form_category.add == false\"\r\n                                v-model=\"form.category_id\"\r\n                                filterable\r\n                                clearable\r\n                            >\r\n                                <el-option\r\n                                    v-for=\"option in categories\"\r\n                                    :key=\"option.id\"\r\n                                    :value=\"option.id\"\r\n                                    :label=\"option.name\"\r\n                                ></el-option>\r\n                            </el-select>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.category_id\"\r\n                                v-text=\"errors.category_id[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <!-- <div class=\"col-md-3\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.web_platform_id}\">\r\n                            <label class=\"control-label\">Plataforma</label>\r\n                            <el-select v-model=\"form.web_platform_id\">\r\n                                <el-option v-for=\"option in web_platforms\" :key=\"option.id\" :value=\"option.id\" :label=\"option.name\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.web_platform_id\" v-text=\"errors.web_platform_id[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n\r\n                    <div class=\"col-md-3 mt-4\">\r\n                        <el-button\r\n                            type=\"primary\"\r\n                            icon=\"el-icon-plus\"\r\n                            @click.prevent=\"showDialogAddItem = true\"\r\n                            >Agregar productos</el-button\r\n                        >\r\n                    </div>\r\n\r\n                    <div\r\n                        class=\"col-md-12 mt-2\"\r\n                        v-if=\"form.individual_items.length > 0\"\r\n                    >\r\n                        <div class=\"table-responsive\">\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>#</th>\r\n                                        <th class=\"font-weight-bold\">\r\n                                            Descripción\r\n                                        </th>\r\n                                        <th\r\n                                            class=\"text-center font-weight-bold\"\r\n                                        >\r\n                                            Precio Unitario\r\n                                        </th>\r\n                                        <th class=\"text-right font-weight-bold\">\r\n                                            Cantidad\r\n                                        </th>\r\n                                        <th></th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr\r\n                                        v-for=\"(row,\r\n                                        index) in form.individual_items\"\r\n                                        :key=\"index\"\r\n                                    >\r\n                                        <td>{{ index + 1 }}</td>\r\n                                        <td>{{ row.full_description }}</td>\r\n                                        <td class=\"text-center\">\r\n                                            {{ row.sale_unit_price }}\r\n                                        </td>\r\n                                        <td class=\"text-right\">\r\n                                            {{ row.quantity }}\r\n                                        </td>\r\n                                        <td class=\"text-right\">\r\n                                            <button\r\n                                                type=\"button\"\r\n                                                class=\"btn waves-effect waves-light btn-xs btn-danger\"\r\n                                                @click.prevent=\"\r\n                                                    clickRemoveItem(index)\r\n                                                \"\r\n                                            >\r\n                                                x\r\n                                            </button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n                        </div>\r\n                    </div>\r\n                    <div\r\n                        class=\"col-md-3\"\r\n                        v-show=\"recordId == null && form.unit_type_id != 'ZZ'\"\r\n                    >\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.stock }\"\r\n                        >\r\n                            <label class=\"control-label\">Stock Inicial</label>\r\n                            <el-input v-model=\"form.stock\"></el-input>\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.stock\"\r\n                                v-text=\"errors.stock[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <!--\r\n                    <div class=\"col-md-3\" v-show=\"form.unit_type_id !='ZZ'\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.stock_min}\">\r\n                            <label class=\"control-label\">Stock Mínimo</label>\r\n                            <el-input v-model=\"form.stock_min\"></el-input>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.stock_min\" v-text=\"errors.stock_min[0]\"></small>\r\n                        </div>\r\n                    </div> -->\r\n\r\n                    <!-- <div class=\"col-md-3 center-el-checkbox\" >\r\n                        <div class=\"form-group\"  >\r\n                            <el-checkbox v-model=\"form.has_perception\" @change=\"changeHasPerception\">Incluye percepción</el-checkbox><br>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-3 center-el-checkbox\" v-show=\"form.has_perception\">\r\n                        <div class=\"form-group\"  >\r\n                            <label class=\"control-label\">Porcentaje de percepción</label>\r\n\r\n                            <el-input v-model=\"form.percentage_perception\"></el-input>\r\n                        </div>\r\n                    </div> -->\r\n                    <!-- <div class=\"col-md-3\" v-show=\"recordId==null\">\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.warehouse_id}\">\r\n                            <label class=\"control-label\">\r\n                                Almacén\r\n                                <el-tooltip class=\"item\" effect=\"dark\" content=\"Si no selecciona almacén, se asignará por defecto el relacionado al establecimiento\" placement=\"top\">\r\n                                    <i class=\"fa fa-info-circle\"></i>\r\n                                </el-tooltip>\r\n                            </label>\r\n                            <el-select v-model=\"form.warehouse_id\" filterable >\r\n                                <el-option v-for=\"option in warehouses\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                            </el-select>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.warehouse_id\" v-text=\"errors.warehouse_id[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <div class=\"col-md-3 \" >\r\n                        <div class=\"form-group\" :class=\"{'has-danger': errors.date_of_due}\">\r\n                            <label class=\"control-label\">Fec. Vencimiento</label>\r\n                            <el-date-picker v-model=\"form.date_of_due\" type=\"date\" value-format=\"yyyy-MM-dd\" :clearable=\"true\"></el-date-picker>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.date_of_due\" v-text=\"errors.date_of_due[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-12\">\r\n                        <h5 class=\"separator-title \">\r\n                            Listado de precios\r\n                            <el-tooltip class=\"item\" effect=\"dark\" content=\"Diferentes presentaciones para la venta del producto\" placement=\"top\">\r\n                                <i class=\"fa fa-info-circle\"></i>\r\n                            </el-tooltip>\r\n                             <a href=\"#\" class=\"control-label font-weight-bold text-info\" @click=\"clickAddRow\"> [ + Nuevo]</a>\r\n                        </h5>\r\n                    </div>\r\n                    <div class=\"col-md-12\" v-if=\"form.item_unit_types.length > 0\">\r\n                    <div class=\"table-responsive\">\r\n                        <table class=\"table\">\r\n                            <thead>\r\n                            <tr>\r\n                                <th class=\"text-center\">Unidad</th>\r\n                                <th class=\"text-center\">Descripción</th>\r\n                                <th class=\"text-center\">\r\n                                    Factor\r\n                                    <el-tooltip class=\"item\" effect=\"dark\" content=\"Cantidad de unidades\" placement=\"top\">\r\n                                        <i class=\"fa fa-info-circle\"></i>\r\n                                    </el-tooltip>\r\n                                </th>\r\n                                <th class=\"text-center\">Precio 1</th>\r\n                                <th class=\"text-center\">Precio 2</th>\r\n                                <th class=\"text-center\">Precio 3</th>\r\n                                <th class=\"text-center\">P. Defecto</th>\r\n                                <th></th>\r\n                            </tr>\r\n                            </thead>\r\n                            <tbody>\r\n                            <tr v-for=\"(row, index) in form.item_unit_types\">\r\n                                <template v-if=\"row.id\">\r\n                                    <td class=\"text-center\">{{row.unit_type_id}}</td>\r\n                                    <td class=\"text-center\">{{row.description}}</td>\r\n                                    <td class=\"text-center\">{{row.quantity_unit}}</td>\r\n                                    <td class=\"text-center\">{{row.price1}}</td>\r\n                                    <td class=\"text-center\">{{row.price2}}</td>\r\n                                    <td class=\"text-center\">{{row.price3}}</td>\r\n                                    <td class=\"text-center\">Precio {{row.price_default}}</td>\r\n                                    <td class=\"series-table-actions text-right\">\r\n                                       <button type=\"button\" class=\"btn waves-effect waves-light btn-xs btn-danger\" @click.prevent=\"clickDelete(row.id)\">\r\n                                            <i class=\"fa fa-trash\"></i>\r\n                                        </button>\r\n                                    </td>\r\n                                </template>\r\n                                <template v-else>\r\n                                    <td>\r\n                                        <div class=\"form-group\"  >\r\n                                            <el-select v-model=\"row.unit_type_id\" dusk=\"item_unit_type.unit_type_id\">\r\n                                                <el-option v-for=\"option in unit_types\" :key=\"option.id\" :value=\"option.id\" :label=\"option.description\"></el-option>\r\n                                            </el-select>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"form-group\" >\r\n                                           <el-input v-model=\"row.description\"></el-input>\r\n                                       </div>\r\n                                    </td>\r\n                                    <td>\r\n                                         <div class=\"form-group\" >\r\n                                            <el-input v-model=\"row.quantity_unit\"></el-input>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"form-group\" >\r\n                                            <el-input v-model=\"row.price1\"></el-input>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"form-group\">\r\n                                            <el-input v-model=\"row.price2\"></el-input>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div class=\"form-group\">\r\n                                            <el-input v-model=\"row.price3\"></el-input>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td>\r\n                                        <div>\r\n                                            <el-radio-group v-model=\"row.price_default\">\r\n                                                <el-radio :label=\"1\" class=\"d-block\">Precio 1</el-radio>\r\n                                                <el-radio :label=\"2\" class=\"d-block\">Precio 2</el-radio>\r\n                                                <el-radio :label=\"3\" class=\"d-block\">Precio 3</el-radio>\r\n                                            </el-radio-group>\r\n                                        </div>\r\n                                    </td>\r\n                                    <td class=\"series-table-actions text-right\">\r\n                                        <button type=\"button\" class=\"btn waves-effect waves-light btn-xs btn-danger\" @click.prevent=\"clickCancel(index)\">\r\n                                            <i class=\"fa fa-trash\"></i>\r\n                                        </button>\r\n                                    </td>\r\n                                </template>\r\n                            </tr>\r\n                            </tbody>\r\n                        </table>\r\n\r\n                    </div> -->\r\n                    <!-- </div>    -->\r\n\r\n                    <div class=\"col-md-12\">\r\n                        <h5 class=\"separator-title\">Campos adicionales</h5>\r\n                    </div>\r\n                    <div class=\"row col-md-12\">\r\n                        <div class=\"col-md-3\">\r\n                            <div class=\"form-group\">\r\n                                <label class=\"control-label\"\r\n                                    >Imágen <span class=\"text-danger\"></span\r\n                                ></label>\r\n                                <el-upload\r\n                                    class=\"avatar-uploader\"\r\n                                    :data=\"{ type: 'items' }\"\r\n                                    :headers=\"headers\"\r\n                                    :action=\"`/${resource}/upload`\"\r\n                                    :show-file-list=\"false\"\r\n                                    :on-success=\"onSuccess\"\r\n                                >\r\n                                    <img\r\n                                        v-if=\"form.image_url\"\r\n                                        :src=\"form.image_url\"\r\n                                        class=\"avatar\"\r\n                                    />\r\n                                    <i\r\n                                        v-else\r\n                                        class=\"el-icon-plus avatar-uploader-icon\"\r\n                                    ></i>\r\n                                </el-upload>\r\n                            </div>\r\n                        </div>\r\n\r\n                        <div class=\"col-md-9\">\r\n                            <div class=\"row\">\r\n                                <div class=\"short-div col-md-8\">\r\n                                    <div\r\n                                        class=\"form-group\"\r\n                                        :class=\"{\r\n                                            'has-danger':\r\n                                                errors.purchase_affectation_igv_type_id\r\n                                        }\"\r\n                                    >\r\n                                        <label class=\"control-label\"\r\n                                            >Tipo de afectación (Venta)</label\r\n                                        >\r\n                                        <el-select\r\n                                            v-model=\"\r\n                                                form.sale_affectation_igv_type_id\r\n                                            \"\r\n                                            @change=\"changeAffectationIgvType\"\r\n                                        >\r\n                                            <el-option\r\n                                                v-for=\"option in affectation_igv_types\"\r\n                                                :key=\"option.id\"\r\n                                                :value=\"option.id\"\r\n                                                :label=\"option.description\"\r\n                                            ></el-option>\r\n                                        </el-select>\r\n                                        <small\r\n                                            class=\"form-control-feedback\"\r\n                                            v-if=\"\r\n                                                errors.sale_affectation_igv_type_id\r\n                                            \"\r\n                                            v-text=\"\r\n                                                errors\r\n                                                    .sale_affectation_igv_type_id[0]\r\n                                            \"\r\n                                        ></small>\r\n                                    </div>\r\n                                </div>\r\n\r\n                                <div class=\"short-div col-md-4\">\r\n                                    <div\r\n                                        class=\"form-group\"\r\n                                        :class=\"{\r\n                                            'has-danger': errors.item_code\r\n                                        }\"\r\n                                    >\r\n                                        <label class=\"control-label\"\r\n                                            >Código Sunat\r\n                                            <el-tooltip\r\n                                                class=\"item\"\r\n                                                effect=\"dark\"\r\n                                                content=\"Código proporcionado por SUNAT, campo obligatorio para exportaciones\"\r\n                                                placement=\"top\"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fa fa-info-circle\"\r\n                                                ></i>\r\n                                            </el-tooltip>\r\n                                        </label>\r\n                                        <el-input\r\n                                            v-model=\"form.item_code\"\r\n                                            dusk=\"item_code\"\r\n                                        ></el-input>\r\n                                        <small\r\n                                            class=\"form-control-feedback\"\r\n                                            v-if=\"errors.item_code\"\r\n                                            v-text=\"errors.item_code[0]\"\r\n                                        ></small>\r\n                                    </div>\r\n                                </div>\r\n                                <div class=\"short-div col-md-4\">\r\n                                    <div\r\n                                        class=\"form-group\"\r\n                                        :class=\"{\r\n                                            'has-danger': errors.internal_id\r\n                                        }\"\r\n                                    >\r\n                                        <label class=\"control-label\"\r\n                                            >Código Interno\r\n                                            <el-tooltip\r\n                                                class=\"item\"\r\n                                                effect=\"dark\"\r\n                                                content=\"Código interno de la empresa para el control de sus productos\"\r\n                                                placement=\"top-start\"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fa fa-info-circle\"\r\n                                                ></i>\r\n                                            </el-tooltip>\r\n                                        </label>\r\n                                        <el-input\r\n                                            v-model=\"form.internal_id\"\r\n                                            dusk=\"internal_id\"\r\n                                        ></el-input>\r\n                                        <small\r\n                                            class=\"form-control-feedback\"\r\n                                            v-if=\"errors.internal_id\"\r\n                                            v-text=\"errors.internal_id[0]\"\r\n                                        ></small>\r\n                                    </div>\r\n                                </div>\r\n                            </div>\r\n                        </div>\r\n                    </div>\r\n\r\n                    <item-set-form-item\r\n                        :showDialog.sync=\"showDialogAddItem\"\r\n                        @add=\"addRow\"\r\n                    ></item-set-form-item>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right pt-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport ItemSetFormItem from \"./partials/item.vue\";\r\n\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"external\"],\r\n    components: { ItemSetFormItem },\r\n\r\n    data() {\r\n        return {\r\n            showDialogAddItem: false,\r\n            warehouses: [],\r\n            loading_submit: false,\r\n            showPercentagePerception: false,\r\n            has_percentage_perception: false,\r\n            percentage_perception: null,\r\n            enabled_percentage_of_profit: false,\r\n            titleDialog: null,\r\n            resource: \"item-sets\",\r\n            errors: {},\r\n            headers: headers_token,\r\n            form_category: { add: false, name: null, id: null },\r\n            form: {},\r\n            areas: [],\r\n            categories: [],\r\n            unit_types: [],\r\n            currency_types: [],\r\n            individual_items: [],\r\n            system_isc_types: [],\r\n            affectation_igv_types: [],\r\n            accounts: [],\r\n            show_has_igv: true,\r\n            have_account: false,\r\n            web_platforms: [],\r\n            item_unit_type: {\r\n                id: null,\r\n                unit_type_id: null,\r\n                quantity_unit: 0,\r\n                price1: 0,\r\n                price2: 0,\r\n                price3: 0,\r\n                price_default: 2\r\n            }\r\n        };\r\n    },\r\n    created() {\r\n        this.initForm();\r\n        this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.unit_types = response.data.unit_types;\r\n            this.accounts = response.data.accounts;\r\n            this.currency_types = response.data.currency_types;\r\n            this.system_isc_types = response.data.system_isc_types;\r\n            this.affectation_igv_types = response.data.affectation_igv_types;\r\n            this.areas = response.data.areas;\r\n            this.categories = response.data.categories;\r\n            // this.individual_items = response.data.individual_items\r\n            this.warehouses = response.data.warehouses;\r\n            this.web_platforms = response.data.web_platforms;\r\n\r\n            this.form.sale_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.form.purchase_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n        });\r\n\r\n        this.$eventHub.$on(\"submitPercentagePerception\", data => {\r\n            this.form.percentage_perception = data;\r\n            if (!this.form.percentage_perception)\r\n                this.has_percentage_perception = false;\r\n        });\r\n    },\r\n    methods: {\r\n        clickRemoveItem(index) {\r\n            this.form.individual_items.splice(index, 1);\r\n            this.changeIndividualItems();\r\n        },\r\n        addRow(row) {\r\n            let exist = this.form.individual_items.find(\r\n                item => item.individual_item_id == row.individual_item_id\r\n            );\r\n\r\n            if (exist) {\r\n                exist.quantity += row.quantity;\r\n            } else {\r\n                this.form.individual_items.push(row);\r\n            }\r\n            // console.log(row)\r\n            this.changeIndividualItems();\r\n        },\r\n        saveCategory() {\r\n            this.form_category.add = false;\r\n\r\n            this.$http\r\n                .post(`/items/categories`, this.form_category)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.categories.push(response.data.data);\r\n                        this.form.category_id = response.data.data.id;\r\n                        this.form_category.name = null;\r\n                    } else {\r\n                        this.$toast.error(\"No se guardaron los cambios\");\r\n                    }\r\n                })\r\n                .catch(error => {\r\n\r\n                })\r\n            },\r\n            changeIndividualItems(){\r\n\r\n                // let acum_sale_unit_price = 0\r\n\r\n                // this.form.individual_items.forEach(row => {\r\n                //     // let individual_item = _.find(this.individual_items,{'id':id})\r\n                //     acum_sale_unit_price += parseFloat(row.sale_unit_price) * parseFloat(row.quantity)\r\n                // });\r\n\r\n                // this.form.sale_unit_price = acum_sale_unit_price\r\n                // this.form.sale_unit_price_set = acum_sale_unit_price\r\n\r\n            },\r\n            initForm() {\r\n                this.loading_submit = false,\r\n                this.errors = {}\r\n                this.form = {\r\n                    id: null,\r\n                    item_type_id: '01',\r\n                    internal_id: null,\r\n                    item_code: null,\r\n                    item_code_gs1: null,\r\n                    description: null,\r\n                    name: null,\r\n                    second_name: null,\r\n                    unit_type_id: 'NIU',\r\n                    currency_type_id: 'PEN',\r\n                    sale_unit_price: 0,\r\n                    purchase_unit_price: 0,\r\n                    has_isc: false,\r\n                    system_isc_type_id: null,\r\n                    percentage_isc: 0,\r\n                    suggested_price: 0,\r\n                    sale_affectation_igv_type_id: null,\r\n                    purchase_affectation_igv_type_id: null,\r\n                    calculate_quantity: false,\r\n                    stock: 0,\r\n                    stock_min: 1,\r\n                    has_igv: true,\r\n                    has_perception: false,\r\n                    item_unit_types:[],\r\n                    percentage_of_profit: 0,\r\n                    percentage_perception: 0,\r\n                    image: null,\r\n                    image_url: null,\r\n                    temp_path: null,\r\n                    account_id: null,\r\n                    is_set: true,\r\n                    sale_unit_price_set: 0,\r\n                    date_of_due:null,\r\n                    web_platform_id:null,\r\n                    category_id:null,\r\n                    area_id:null,\r\n                    individual_items:[],\r\n                    attributes: []\r\n                }\r\n                this.show_has_igv = true\r\n                this.enabled_percentage_of_profit = false\r\n            },\r\n            onSuccess(response, file, fileList) {\r\n                if (response.success) {\r\n                    this.form.image = response.data.filename\r\n                    this.form.image_url = response.data.temp_image\r\n                    this.form.temp_path = response.data.temp_path\r\n                } else {\r\n                    this.$toast.error(response.message)\r\n                }\r\n            },\r\n            changeAffectationIgvType(){\r\n\r\n            if (is_exonerated) {\r\n                this.show_has_igv = false;\r\n                this.form.has_igv = true;\r\n            } else {\r\n                this.show_has_igv = true;\r\n            }\r\n        },\r\n        resetForm() {\r\n            this.initForm();\r\n            this.form.sale_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n            this.form.purchase_affectation_igv_type_id =\r\n                this.affectation_igv_types.length > 0\r\n                    ? this.affectation_igv_types[0].id\r\n                    : null;\r\n        },\r\n        create() {\r\n            this.titleDialog = this.recordId\r\n                ? \"Editar producto compuesto\"\r\n                : \"Nuevo producto compuesto\";\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.changeAffectationIgvType();\r\n                    });\r\n            }\r\n        },\r\n        loadRecord() {\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                        this.changeAffectationIgvType();\r\n                    });\r\n            }\r\n        },\r\n\r\n        changeHaveAccount() {\r\n            if (!this.have_account) this.form.account_id = null;\r\n        },\r\n        changeEnabledPercentageOfProfit() {\r\n            // if(!this.enabled_percentage_of_profit) this.form.percentage_of_profit = 0\r\n        },\r\n        clickDelete(id) {\r\n            this.$http\r\n                .delete(`/${this.resource}/item-unit-type/${id}`)\r\n                .then(res => {\r\n                    if (res.data.success) {\r\n                        this.loadRecord();\r\n                        this.$toast.success(\r\n                            \"Se eliminó correctamente el registro\"\r\n                        );\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 500) {\r\n                        this.$toast.error(\"Error al intentar eliminar\");\r\n                    } else {\r\n                        console.log(error.response.data.message);\r\n                    }\r\n                });\r\n        },\r\n        changeHasPerception() {\r\n            if (!this.form.has_perception) {\r\n                this.form.percentage_perception = null;\r\n            }\r\n        },\r\n        clickAddRow() {\r\n            this.form.item_unit_types.push({\r\n                id: null,\r\n                description: null,\r\n                unit_type_id: \"NIU\",\r\n                quantity_unit: 0,\r\n                price1: 0,\r\n                price2: 0,\r\n                price3: 0,\r\n                price_default: 2\r\n            });\r\n        },\r\n        clickCancel(index) {\r\n            this.form.item_unit_types.splice(index, 1);\r\n            // this.initDocumentTypes()\r\n            // this.showAddButton = true\r\n        },\r\n        calculatePercentageOfProfitBySale() {\r\n            let difference =\r\n                parseFloat(this.form.sale_unit_price) -\r\n                parseFloat(this.form.purchase_unit_price);\r\n\r\n            if (parseFloat(this.form.purchase_unit_price) === 0) {\r\n                this.form.percentage_of_profit = 0;\r\n            } else {\r\n                if (this.enabled_percentage_of_profit)\r\n                    this.form.percentage_of_profit =\r\n                        (difference /\r\n                            parseFloat(this.form.purchase_unit_price)) *\r\n                        100;\r\n            }\r\n        },\r\n        calculatePercentageOfProfitByPurchase() {\r\n            if (this.form.percentage_of_profit === \"\") {\r\n                this.form.percentage_of_profit = 0;\r\n            }\r\n\r\n            if (this.enabled_percentage_of_profit)\r\n                this.form.sale_unit_price =\r\n                    (this.form.purchase_unit_price *\r\n                        (100 + parseFloat(this.form.percentage_of_profit))) /\r\n                    100;\r\n        },\r\n        calculatePercentageOfProfitByPercentage() {\r\n            if (this.form.percentage_of_profit === \"\") {\r\n                this.form.percentage_of_profit = 0;\r\n            }\r\n\r\n            if (this.enabled_percentage_of_profit)\r\n                this.form.sale_unit_price =\r\n                    (this.form.purchase_unit_price *\r\n                        (100 + parseFloat(this.form.percentage_of_profit))) /\r\n                    100;\r\n        },\r\n        submit() {\r\n            if (this.form.individual_items.length < 1)\r\n                return this.$toast.error(\"Al menos debe elegir 2 productos\");\r\n                \r\n\r\n            this.form.sale_unit_price_set = this.form.sale_unit_price;\r\n            this.form.attributes = this.form.attributes\r\n                ? this.form.attributes\r\n                : [];\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        if (this.external) {\r\n                            this.$eventHub.$emit(\r\n                                \"reloadDataItems\",\r\n                                response.data.id\r\n                            );\r\n                        } else {\r\n                            this.$eventHub.$emit(\"reloadData\");\r\n                        }\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.resetForm();\r\n        },\r\n        changeHasIsc() {\r\n            this.form.system_isc_type_id = null;\r\n            this.form.percentage_isc = 0;\r\n            this.form.suggested_price = 0;\r\n        },\r\n        changeSystemIscType() {\r\n            if (this.form.system_isc_type_id !== \"03\") {\r\n                this.form.suggested_price = 0;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/item_sets/form.vue","<template>\r\n    <el-dialog :title=\"titleDialog\" :visible=\"showDialog\" @close=\"close\" @open=\"create\" class=\"dialog-import\">\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <a href=\"/formats/item_sets.xlsx\" target=\"_new\">Descargar formato</a>\r\n                    </div>\r\n                    <div class=\"col-md-12 mt-4\">\r\n                        <div class=\"form-group text-center\" :class=\"{'has-danger': errors.file}\">\r\n                            <el-upload\r\n                                    ref=\"upload\"\r\n                                    :headers=\"headers\"\r\n                                    action=\"/items/import/item-sets\"\r\n                                    :show-file-list=\"true\"\r\n                                    :auto-upload=\"false\"\r\n                                    :multiple=\"false\"\r\n                                    :on-error=\"errorUpload\"\r\n                                    :limit=\"1\"\r\n                                    :on-success=\"successUpload\">\r\n                                <el-button slot=\"trigger\" type=\"primary\">Seleccione un archivo (xlsx)</el-button>\r\n                            </el-upload>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.file\" v-text=\"errors.file[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right mt-4\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button type=\"primary\" native-type=\"submit\" :loading=\"loading_submit\">Procesar</el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\n    export default {\r\n        props: ['showDialog'],\r\n        data() {\r\n            return {\r\n                loading_submit: false,\r\n                headers: headers_token,\r\n                titleDialog: null,\r\n                resource: 'items',\r\n                errors: {},\r\n                form: {},\r\n            }\r\n        },\r\n        created() {\r\n            this.initForm()\r\n        },\r\n        methods: {\r\n            initForm() {\r\n                this.errors = {}\r\n                this.form = {\r\n                    file: null,\r\n                }\r\n            },\r\n            create() {\r\n                this.titleDialog = 'Importar Productos Compuestos'\r\n            },\r\n            async submit() {\r\n                this.loading_submit = true\r\n                await this.$refs.upload.submit()\r\n                this.loading_submit = false\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.initForm()\r\n            },\r\n            successUpload(response, file, fileList) {\r\n                if (response.success) {\r\n                    this.$toast.success(response.message)\r\n                    this.$eventHub.$emit('reloadData')\r\n                    this.$refs.upload.clearFiles()\r\n                    this.close()\r\n                } else {\r\n                    this.$toast.error(response.message);\r\n                }\r\n            },\r\n         