ialog :title=\"titleDialog\" :visible=\"showDialog\" @close=\"close\" @open=\"create\" class=\"dialog-import\">\r\n        <form autocomplete=\"off\" @submit.prevent=\"submit\">\r\n            <div class=\"form-body\">\r\n                <div class=\"row\">\r\n                    <div class=\"col-md-12\">\r\n                        <a href=\"/formats/item_sets_individual.xlsx\" target=\"_new\">Descargar formato</a>\r\n                    </div>\r\n                    <div class=\"col-md-12 mt-4\">\r\n                        <div class=\"form-group text-center\" :class=\"{'has-danger': errors.file}\">\r\n                            <el-upload\r\n                                    ref=\"upload\"\r\n                                    :headers=\"headers\"\r\n                                    action=\"/items/import/item-sets-individual\"\r\n                                    :show-file-list=\"true\"\r\n                                    :auto-upload=\"false\"\r\n                                    :multiple=\"false\"\r\n                                    :on-error=\"errorUpload\"\r\n                                    :limit=\"1\"\r\n                                    :on-success=\"successUpload\">\r\n                                <el-button slot=\"trigger\" type=\"primary\">Seleccione un archivo (xlsx)</el-button>\r\n                            </el-upload>\r\n                            <small class=\"form-control-feedback\" v-if=\"errors.file\" v-text=\"errors.file[0]\"></small>\r\n                        </div>\r\n                    </div>\r\n\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-right mt-4\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button type=\"primary\" native-type=\"submit\" :loading=\"loading_submit\">Procesar</el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n\r\n    export default {\r\n        props: ['showDialog'],\r\n        data() {\r\n            return {\r\n                loading_submit: false,\r\n                headers: headers_token,\r\n                titleDialog: null,\r\n                resource: 'items',\r\n                errors: {},\r\n                form: {},\r\n            }\r\n        },\r\n        created() {\r\n            this.initForm()\r\n        },\r\n        methods: {\r\n            initForm() {\r\n                this.errors = {}\r\n                this.form = {\r\n                    file: null,\r\n                }\r\n            },\r\n            create() {\r\n                this.titleDialog = 'Importar detalle de productos compuestos'\r\n            },\r\n            async submit() {\r\n                this.loading_submit = true\r\n                await this.$refs.upload.submit()\r\n                this.loading_submit = false\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.initForm()\r\n            },\r\n            successUpload(response, file, fileList) {\r\n                if (response.success) {\r\n                    this.$toast.success(response.message)\r\n                    this.$eventHub.$emit('reloadData')\r\n                    this.$eventHub.$emit('reloadTables')\r\n                    this.$refs.upload.clearFiles()\r\n                    this.close()\r\n                } else {\r\n                    this.$toast.error(response.message);\r\n                }\r\n            },\r\n            errorUpload(response) {\r\n                console.log(response)\r\n            }\r\n        }\r\n    }\r\n</script>\n\n\n// WEBPACK FOOTER //\n// resources/js/views/item_sets/partials/import_set_individual.vue","<template>\r\n    <el-dialog :title=\"titleDialog\" :visible=\"showDialog\" @open=\"create\" @close=\"close\"  append-to-body >\r\n        <form autocomplete=\"off\" @submit.prevent=\"clickAddItem\">\r\n            <div clas